"use client";
import { useState } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";

export default function RegisterPage() {
    const [username, setUsername] = useState("");
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [confirmPassword, setConfirmPassword] = useState("");
    const [error, setError] = useState("");
    const router = useRouter();

    const isPasswordValid = password.length >= 8;
    const isMatch = password === confirmPassword && confirmPassword !== "";

    const handleRegister = async (e: React.FormEvent) => {
        e.preventDefault();
        setError("");

        if (!isPasswordValid) return setError("Password minimal 8 karakter!");
        if (!isMatch) return setError("Password tidak cocok!");

        const res = await fetch("/api/register", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ username, email, password, confirmPassword }),
        });

        if (res.ok) {
        alert("✅ Akun berhasil dibuat! Silakan Login.");
        router.push("/login");
        } else {
        const data = await res.json();
        setError(data.error || "Gagal mendaftar");
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center bg-[#0f172a] p-4">
        <div className="bg-white p-8 rounded-2xl shadow-2xl w-full max-w-sm">
            <h1 className="text-2xl font-bold mb-6 text-slate-800 text-center">Daftar Akun Baru</h1>
            
            {error && <p className="bg-red-50 text-red-500 p-2 rounded text-xs mb-4 border border-red-100">{error}</p>}

            <form onSubmit={handleRegister} className="space-y-4">
            <input
                type="text"
                placeholder="Username"
                className="w-full p-3 border border-slate-200 rounded-lg text-slate-800 focus:outline-none focus:ring-2 focus:ring-blue-500"
                onChange={(e) => setUsername(e.target.value)}
                required
            />
            <input
                type="email"
                placeholder="Email"
                className="w-full p-3 border border-slate-200 rounded-lg text-slate-800 focus:outline-none focus:ring-2 focus:ring-blue-500"
                onChange={(e) => setEmail(e.target.value)}
                required
            />
            <input
                type="password"
                placeholder="Password (Min 8 Karakter)"
                className={`w-full p-3 border rounded-lg text-slate-800 focus:outline-none focus:ring-2 focus:ring-blue-500 ${password && !isPasswordValid ? 'border-red-500' : 'border-slate-200'}`}
                onChange={(e) => setPassword(e.target.value)}
                required
            />
            <input
                type="password"
                placeholder="Confirm Password"
                className={`w-full p-3 border rounded-lg text-slate-800 focus:outline-none focus:ring-2 focus:ring-blue-500 ${confirmPassword && !isMatch ? 'border-red-500' : 'border-slate-200'}`}
                onChange={(e) => setConfirmPassword(e.target.value)}
                required
            />
            
            <button 
                disabled={!isPasswordValid || !isMatch}
                className="w-full bg-emerald-600 text-white p-3 rounded-lg font-bold hover:bg-emerald-700 transition duration-200 disabled:bg-slate-300"
            >
                Sign Up
            </button>
            </form>

            <p className="mt-6 text-center text-sm text-slate-500">
            Sudah punya akun? {" "}
            <Link href="/login" className="text-blue-600 font-bold hover:underline">
                Login di sini
            </Link>
            </p>
        </div>
        </div>
    );
}